// ═══════════════════════════════════════════════════════════
// ÉTAPE 0 — Extraction payload + paramètres par défaut
// ═══════════════════════════════════════════════════════════
const body = $input.first().json.body;
const info = body.informationsGenerales || {};
const ressources = body.ressources || {};

// --- Extraction payload brut ---
const payload = {
  type: body.type || 'COURTE',
  codeFormation: info.codeFormation || body.codeFormation,
  dateDebut: info.dateDebut || body.dateDebut,
  dateFin: info.dateFin || body.dateFin,
  dureeHeures: Number(info.dureeHeures || body.dureeHeures),
  heuresParJour: Number(info.heuresParJour || body.heuresParJour || 7),
  nbSeances: Number(info.nbSeances || body.nbSeances || 0),
  nbParticipants: Number(info.nbParticipants || body.nbParticipants || body.capaciteMax || 8),
  joursActifs: body.joursActifs || ['LUNDI','MARDI','MERCREDI','JEUDI','VENDREDI'],
  salleId: ressources.salleId || body.salleId || null,
  formateurId: ressources.formateurId || body.formateurId || null,
  sourceForm: body.sourceForm || 'CRM',
  demandePar: body.demandePar || null
};

// --- Calculer nbSeances si pas fourni ---
if (!payload.nbSeances || payload.nbSeances === 0) {
  payload.nbSeances = Math.ceil(payload.dureeHeures / payload.heuresParJour);
}

// --- Observations (texte libre) ---
const observations = (body.notesComplementaires || body.notes || '').trim();
const needsAIParsing = observations.length > 0 
  && observations.toLowerCase() !== 'ras' 
  && observations.toLowerCase() !== 'rien';

// --- Paramètres par défaut (seront surchargés par IA si observations) ---
const paramsDefaut = {
  matinDebut: '09:00',
  matinFin: '12:00',
  amDebut: '13:00',
  amFin: '17:00',
  datesExclues: [],
  sallesExclues: [],
  formateursExclus: [],
  autresContraintes: []
};

// --- Validation basique ---
const erreurs = [];
if (!payload.codeFormation) erreurs.push('codeFormation manquant');
if (!payload.dateDebut) erreurs.push('dateDebut manquant');
if (!payload.dateFin) erreurs.push('dateFin manquant');
if (!payload.dureeHeures || payload.dureeHeures <= 0) erreurs.push('dureeHeures invalide');
if (payload.dateDebut && payload.dateFin && payload.dateDebut >= payload.dateFin) {
  erreurs.push('dateDebut doit etre avant dateFin');
}

return [{
  json: {
    payload,
    observations,
    needsAIParsing,
    paramsDefaut,
    erreurs,
    valide: erreurs.length === 0
  }
}];

// ═══════════════════════════════════════════════════════════
// ÉTAPE 0.5 — Fusionner paramètres défaut + surcharges IA
// ═══════════════════════════════════════════════════════════
const ep = $('Extraire Payload').first().json;
const paramsDefaut = ep.paramsDefaut;
const needsAI = ep.needsAIParsing;

let surcharges = {};

if (needsAI) {
  // L'IA a répondu — parser le JSON
  try {
    const aiOutput = $('IA Parser Observations').first().json.text || $('IA Parser Observations').first().json.response || '';
    const jsonMatch = aiOutput.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      surcharges = JSON.parse(jsonMatch[0]);
    }
  } catch (e) {
    // Si parsing échoue, on continue avec les défauts
    surcharges = {};
  }
}

// Fusionner: défauts + surcharges (les surcharges écrasent les défauts)
const params = {
  matinDebut: surcharges.matinDebut || paramsDefaut.matinDebut,
  matinFin: surcharges.matinFin || paramsDefaut.matinFin,
  amDebut: surcharges.amDebut || paramsDefaut.amDebut,
  amFin: surcharges.amFin || paramsDefaut.amFin,
  datesExclues: surcharges.datesExclues || paramsDefaut.datesExclues,
  sallesExclues: surcharges.sallesExclues || paramsDefaut.sallesExclues,
  formateursExclus: surcharges.formateursExclus || paramsDefaut.formateursExclus,
  autresContraintes: surcharges.autresContraintes || paramsDefaut.autresContraintes
};

// Calculer heures effectives par jour avec les plages
function heuresEntre(debut, fin) {
  const [h1, m1] = debut.split(':').map(Number);
  const [h2, m2] = fin.split(':').map(Number);
  return (h2 + m2/60) - (h1 + m1/60);
}

const heuresMatin = heuresEntre(params.matinDebut, params.matinFin);
const heuresAM = heuresEntre(params.amDebut, params.amFin);
const heuresEffectivesJour = heuresMatin + heuresAM;

params.heuresMatin = heuresMatin;
params.heuresAM = heuresAM;
params.heuresEffectivesJour = heuresEffectivesJour;

// Recalculer nbSeances si heuresParJour a changé via les plages
const payload = ep.payload;
const nbSeancesRecalcule = Math.ceil(payload.dureeHeures / heuresEffectivesJour);

return [{
  json: {
    payload: { ...payload, nbSeances: nbSeancesRecalcule },
    params,
    formation: $('Verifier Formation').first().json,
    surchargesIA: surcharges,
    observationsOriginales: ep.observations
  }
}];

// ═══════════════════════════════════════════════════════════
// ÉTAPE 1 — Calculer les dates candidates
// ═══════════════════════════════════════════════════════════
const { payload, params } = $input.first().json;

const JOURS_MAP = {
  'LUNDI': 1, 'MARDI': 2, 'MERCREDI': 3, 'JEUDI': 4,
  'VENDREDI': 5, 'SAMEDI': 6, 'DIMANCHE': 0
};

const joursActifsNum = payload.joursActifs.map(j => JOURS_MAP[j]);
const datesExcluesSet = new Set(params.datesExclues || []);

const dates = [];
const start = new Date(payload.dateDebut + 'T00:00:00');
const end = new Date(payload.dateFin + 'T00:00:00');

for (let d = new Date(start); d <= end; d.setDate(d.getDate() + 1)) {
  const dayOfWeek = d.getDay();
  if (!joursActifsNum.includes(dayOfWeek)) continue;

  const dateStr = d.toISOString().split('T')[0];
  if (datesExcluesSet.has(dateStr)) continue;

  dates.push(dateStr);
}

// Vérification: assez de dates candidates?
const nbSeancesRequises = payload.nbSeances;
const assezDeDates = dates.length >= nbSeancesRequises;

// Construire la liste SQL pour les requêtes suivantes
const datesSql = dates.map(d => `'${d}'`).join(',');

return [{
  json: {
    payload: $input.first().json.payload,
    params: $input.first().json.params,
    formation: $input.first().json.formation,
    datesCandidates: dates,
    nbDatesCandidates: dates.length,
    nbSeancesRequises,
    assezDeDates,
    datesSql,
    surchargesIA: $input.first().json.surchargesIA,
    observationsOriginales: $input.first().json.observationsOriginales
  }
}];

// ═══════════════════════════════════════════════════════════
// ÉTAPE 3 — Croiser disponibilités : construire la grille
// ═══════════════════════════════════════════════════════════
const prev = $('Calculer Dates Candidates').first().json;
const { payload, params, formation, datesCandidates } = prev;

// Récupérer résultats SQL
const sallesRaw = $('Query Salles').all().map(i => i.json);
const formateursRaw = $('Query Formateurs').all().map(i => i.json);

// --- Parser les réservations existantes par salle ---
const salles = sallesRaw.map(s => {
  let reservations = [];
  try {
    reservations = typeof s.reservations_existantes === 'string' 
      ? JSON.parse(s.reservations_existantes) 
      : (s.reservations_existantes || []);
  } catch(e) { reservations = []; }

  return {
    idSalle: s.id_salle,
    nom: s.nom,
    code: s.code,
    capaciteMax: s.capacite_max,
    reservations: reservations
  };
});

// --- Parser les disponibilités formateurs ---
const formateurs = formateursRaw.map(f => {
  let dispos = [];
  try {
    dispos = typeof f.jours_disponibles === 'string'
      ? JSON.parse(f.jours_disponibles)
      : (f.jours_disponibles || []);
  } catch(e) { dispos = []; }

  // Vérifier si le formateur peut enseigner cette formation
  const formations = f.formations_enseignees || [];
  const peutEnseigner = formations.includes(formation.id_formation);

  return {
    idFormateur: f.id_formateur,
    nom: f.nom,
    prenom: f.prenom,
    nomComplet: f.prenom + ' ' + f.nom,
    specialites: f.specialites || [],
    peutEnseigner,
    joursDisponibles: dispos.map(d => {
      const dateStr = typeof d.date === 'string' ? d.date.split('T')[0] : d.date;
      return dateStr;
    })
  };
}).filter(f => f.peutEnseigner); // Garder que ceux qualifiés

// --- Appliquer exclusions (depuis observations IA) ---
const sallesExclues = new Set((params.sallesExclues || []).map(s => s.toLowerCase()));
const formateursExclus = new Set((params.formateursExclus || []).map(f => f.toLowerCase()));

const sallesFiltrees = salles.filter(s => !sallesExclues.has(s.nom.toLowerCase()));
const formateursFiltres = formateurs.filter(f => 
  !formateursExclus.has(f.nomComplet.toLowerCase()) && 
  !formateursExclus.has(f.nom.toLowerCase())
);

// --- Si salle/formateur imposé, filtrer ---
const sallesFinales = payload.salleId 
  ? sallesFiltrees.filter(s => s.idSalle === payload.salleId)
  : sallesFiltrees;

const formateursFinaux = payload.formateurId
  ? formateursFiltres.filter(f => f.idFormateur === payload.formateurId)
  : formateursFiltres;

// --- Construire la grille par date ---
const grille = datesCandidates.map(date => {
  // Salles libres ce jour
  const sallesLibres = sallesFinales.filter(salle => {
    // Vérifier si la salle a des réservations ce jour qui chevauchent nos plages
    const reservsCeJour = salle.reservations.filter(r => {
      const rDate = typeof r.date === 'string' ? r.date.split('T')[0] : r.date;
      return rDate === date;
    });

    if (reservsCeJour.length === 0) return true; // Aucune réservation = libre

    // Vérifier chevauchement avec nos plages horaires
    const nosPlages = [
      { debut: params.matinDebut, fin: params.matinFin },
      { debut: params.amDebut, fin: params.amFin }
    ];

    for (const reserv of reservsCeJour) {
      for (const plage of nosPlages) {
        // Chevauchement si: reserv.debut < plage.fin ET reserv.fin > plage.debut
        if (reserv.heure_debut < plage.fin && reserv.heure_fin > plage.debut) {
          return false; // Conflit!
        }
      }
    }
    return true; // Pas de chevauchement
  });

  // Formateurs disponibles ce jour
  const formateursDispo = formateursFinaux.filter(f => {
    // Si pas de données de disponibilité, considérer comme potentiellement dispo
    if (f.joursDisponibles.length === 0 && formateursFinaux.length > 0) return true;
    return f.joursDisponibles.includes(date);
  });

  return {
    date,
    sallesLibres: sallesLibres.map(s => ({ idSalle: s.idSalle, nom: s.nom, code: s.code, capaciteMax: s.capaciteMax })),
    formateursDispo: formateursDispo.map(f => ({ idFormateur: f.idFormateur, nomComplet: f.nomComplet })),
    viable: sallesLibres.length > 0 // Au minimum une salle libre
  };
});

// --- Résumé ---
const datesViables = grille.filter(g => g.viable);
const solutionsPossibles = datesViables.length >= payload.nbSeances;

return [{
  json: {
    payload,
    params,
    formation,
    grille,
    datesViables: datesViables.length,
    datesTotales: datesCandidates.length,
    nbSeancesRequises: payload.nbSeances,
    solutionsPossibles,
    sallesDisponibles: sallesFinales.map(s => s.nom),
    formateursQualifies: formateursFinaux.map(f => f.nomComplet),
    surchargesIA: prev.surchargesIA,
    observationsOriginales: prev.observationsOriginales
  }
}];

