// ═══════════════════════════════════════════════════════════
// ÉTAPE 4b — Parser le choix de l'IA
// ═══════════════════════════════════════════════════════════
const aiOutput = $input.first().json.text || $input.first().json.response || '';
const prev = $('Croiser Disponibilites').first().json;

let choix;
try {
  const jsonMatch = aiOutput.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    choix = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('Pas de JSON dans la reponse IA');
  }
} catch (e) {
  return [{
    json: {
      erreur: true,
      message: 'Erreur parsing choix IA: ' + e.message,
      raw: aiOutput
    }
  }];
}

return [{
  json: {
    payload: prev.payload,
    params: prev.params,
    formation: prev.formation,
    choix: choix,
    seances: choix.seances || [],
    raisonnement: choix.raisonnement || '',
    erreur: false
  }
}];

// ═══════════════════════════════════════════════════════════
// ÉTAPE 5 — Générer les créneaux horaires précis
// ═══════════════════════════════════════════════════════════
const { payload, params, formation, seances } = $input.first().json;

const creneaux = [];
let heuresRestantes = payload.dureeHeures;

for (let i = 0; i < seances.length; i++) {
  const seance = seances[i];

  if (heuresRestantes <= 0) break;

  // Calculer heures pour cette séance
  const heuresMatin = Math.min(
    params.heuresMatin, 
    heuresRestantes
  );

  if (heuresMatin > 0) {
    // Calculer heure fin matin exacte
    const [h, m] = params.matinDebut.split(':').map(Number);
    const finMinutes = (h * 60 + m) + (heuresMatin * 60);
    const finH = Math.floor(finMinutes / 60);
    const finM = finMinutes % 60;
    const heureFin = String(finH).padStart(2, '0') + ':' + String(finM).padStart(2, '0');

    creneaux.push({
      date: seance.date,
      heureDebut: params.matinDebut,
      heureFin: Math.min(finMinutes, timeToMin(params.matinFin)) === finMinutes ? heureFin : params.matinFin,
      dureeHeures: heuresMatin,
      periode: 'MATIN',
      idSalle: seance.idSalle,
      nomSalle: seance.nomSalle,
      idFormateur: seance.idFormateur,
      nomFormateur: seance.nomFormateur
    });
    heuresRestantes -= heuresMatin;
  }

  if (heuresRestantes <= 0) break;

  const heuresAM = Math.min(
    params.heuresAM, 
    heuresRestantes
  );

  if (heuresAM > 0) {
    // Calculer heure fin AM exacte
    const [h, m] = params.amDebut.split(':').map(Number);
    const finMinutes = (h * 60 + m) + (heuresAM * 60);
    const finH = Math.floor(finMinutes / 60);
    const finM = finMinutes % 60;
    const heureFin = String(finH).padStart(2, '0') + ':' + String(finM).padStart(2, '0');

    creneaux.push({
      date: seance.date,
      heureDebut: params.amDebut,
      heureFin: Math.min(finMinutes, timeToMin(params.amFin)) === finMinutes ? heureFin : params.amFin,
      dureeHeures: heuresAM,
      periode: 'APRES_MIDI',
      idSalle: seance.idSalle,
      nomSalle: seance.nomSalle,
      idFormateur: seance.idFormateur,
      nomFormateur: seance.nomFormateur
    });
    heuresRestantes -= heuresAM;
  }
}

function timeToMin(t) {
  const [h, m] = t.split(':').map(Number);
  return h * 60 + m;
}

// Arrondir à 30min (granularité)
const creneauxArrondis = creneaux.map(c => {
  // Arrondir heureFin au créneau de 30min supérieur
  const finMin = timeToMin(c.heureFin);
  const arrondi = Math.ceil(finMin / 30) * 30;
  const h = Math.floor(arrondi / 60);
  const m = arrondi % 60;
  return {
    ...c,
    heureFin: String(h).padStart(2, '0') + ':' + String(m).padStart(2, '0')
  };
});

const totalHeuresPlacees = creneauxArrondis.reduce((sum, c) => sum + c.dureeHeures, 0);

return [{
  json: {
    payload,
    params,
    formation,
    seances: $input.first().json.seances,
    raisonnement: $input.first().json.raisonnement,
    creneaux: creneauxArrondis,
    totalHeuresPlacees,
    heuresRestantes: Math.max(0, payload.dureeHeures - totalHeuresPlacees),
    nbCreneaux: creneauxArrondis.length
  }
}];

// ═══════════════════════════════════════════════════════════
// ÉTAPE 6 — Validateur (filet de sécurité)
// ═══════════════════════════════════════════════════════════
const data = $input.first().json;
const { payload, params, formation, creneaux, seances, totalHeuresPlacees } = data;

const erreurs = [];
const warnings = [];

// 1. Nb séances correct?
const datesUniques = [...new Set(creneaux.map(c => c.date))];
if (datesUniques.length !== payload.nbSeances) {
  // Tolérance: si on a placé toutes les heures en moins de séances, c'est OK
  if (datesUniques.length < payload.nbSeances && totalHeuresPlacees >= payload.dureeHeures) {
    warnings.push(`${datesUniques.length} seances au lieu de ${payload.nbSeances} mais toutes les heures sont placees`);
  } else if (datesUniques.length < payload.nbSeances) {
    erreurs.push(`Seulement ${datesUniques.length} seances sur ${payload.nbSeances} requises`);
  }
}

// 2. Total heures = dureeHeures?
const tolerance = 0.5; // 30min de tolérance
if (Math.abs(totalHeuresPlacees - payload.dureeHeures) > tolerance) {
  erreurs.push(`Total heures: ${totalHeuresPlacees}h vs ${payload.dureeHeures}h demandees (ecart > 30min)`);
}

// 3. Dates dans la fenêtre?
const dateDebut = payload.dateDebut;
const dateFin = payload.dateFin;
for (const c of creneaux) {
  if (c.date < dateDebut || c.date > dateFin) {
    erreurs.push(`Creneau ${c.date} hors fenetre ${dateDebut} - ${dateFin}`);
  }
}

// 4. Jours actifs respectés?
const JOURS_MAP = { 0: 'DIMANCHE', 1: 'LUNDI', 2: 'MARDI', 3: 'MERCREDI', 4: 'JEUDI', 5: 'VENDREDI', 6: 'SAMEDI' };
for (const c of creneaux) {
  const jour = JOURS_MAP[new Date(c.date + 'T12:00:00').getDay()];
  if (!payload.joursActifs.includes(jour)) {
    erreurs.push(`Creneau ${c.date} tombe un ${jour}, non actif`);
  }
}

// 5. Pas de salle null?
for (const c of creneaux) {
  if (!c.idSalle) {
    erreurs.push(`Creneau ${c.date} ${c.periode} sans salle assignee`);
  }
}

// 6. Heures arrondies à 30min?
function timeToMin(t) {
  const [h, m] = t.split(':').map(Number);
  return h * 60 + m;
}
for (const c of creneaux) {
  if (timeToMin(c.heureDebut) % 30 !== 0) {
    warnings.push(`Heure debut ${c.heureDebut} non arrondie a 30min`);
  }
  if (timeToMin(c.heureFin) % 30 !== 0) {
    warnings.push(`Heure fin ${c.heureFin} non arrondie a 30min`);
  }
}

// 7. Pause déjeuner respectée? (pas de créneau qui chevauche la pause)
for (const date of datesUniques) {
  const creneauxJour = creneaux.filter(c => c.date === date);
  const matins = creneauxJour.filter(c => c.periode === 'MATIN');
  const ams = creneauxJour.filter(c => c.periode === 'APRES_MIDI');

  for (const m of matins) {
    for (const a of ams) {
      if (timeToMin(m.heureFin) > timeToMin(a.heureDebut)) {
        erreurs.push(`${date}: chevauchement matin/AM (${m.heureFin} > ${a.heureDebut})`);
      }
    }
  }
}

const valide = erreurs.length === 0;

// Construire rapport
const rapport = [
  `Formation: ${formation.nom} (${formation.code_formation})`,
  `Fenetre: ${payload.dateDebut} → ${payload.dateFin}`,
  `${datesUniques.length} seances, ${totalHeuresPlacees}h/${payload.dureeHeures}h`,
  `Salle: ${[...new Set(creneaux.map(c => c.nomSalle))].join(', ')}`,
  `Formateur: ${[...new Set(creneaux.filter(c => c.nomFormateur).map(c => c.nomFormateur))].join(', ') || 'Non assigne'}`,
  data.raisonnement ? `Choix IA: ${data.raisonnement}` : '',
  warnings.length > 0 ? `Warnings: ${warnings.join('; ')}` : '',
  erreurs.length > 0 ? `ERREURS: ${erreurs.join('; ')}` : ''
].filter(l => l).join('\n');

return [{
  json: {
    valide,
    erreurs,
    warnings,
    rapport,
    payload,
    params,
    formation,
    creneaux,
    seances,
    datesUniques,
    totalHeuresPlacees
  }
}];

// ═══════════════════════════════════════════════════════════
// ÉTAPE 7b — Préparer les réservations de salles
// ═══════════════════════════════════════════════════════════
const sessionCreated = $input.first().json;
const idSession = sessionCreated.id_session;
const creneaux = $('Validateur').first().json.creneaux;

const reservations = creneaux.map(c => ({
  json: {
    idSession,
    idSalle: c.idSalle,
    dateDebut: c.date + ' ' + c.heureDebut + ':00+02',
    dateFin: c.date + ' ' + c.heureFin + ':00+02',
    nomSalle: c.nomSalle,
    periode: c.periode
  }
}));

return reservations;

